        const svgNS = "http://www.w3.org/2000/svg";
        const mandalaContainer = document.getElementById('mandalaContainer');
        const mandalaBgRect = document.querySelector('.mandala-bg');
        const cx = 0;
        const cy = 0;

        // Control Element References
        const controls = {
            // General
            segments: document.getElementById('segments'), segmentsValue: document.getElementById('segmentsValue'), polygonSides: document.getElementById('polygonSides'), polygonSidesValue: document.getElementById('polygonSidesValue'), strokeWidth: document.getElementById('strokeWidth'), strokeWidthValue: document.getElementById('strokeWidthValue'),
            // Shape 1-5 Params
            shapeType1: document.getElementById('shapeType1'), distance1: document.getElementById('distance1'), distance1Value: document.getElementById('distance1Value'), size1: document.getElementById('size1'), size1Value: document.getElementById('size1Value'),
            shapeType2: document.getElementById('shapeType2'), distance2: document.getElementById('distance2'), distance2Value: document.getElementById('distance2Value'), size2: document.getElementById('size2'), size2Value: document.getElementById('size2Value'),
            shapeType3: document.getElementById('shapeType3'), distance3: document.getElementById('distance3'), distance3Value: document.getElementById('distance3Value'), size3: document.getElementById('size3'), size3Value: document.getElementById('size3Value'),
            shapeType4: document.getElementById('shapeType4'), distance4: document.getElementById('distance4'), distance4Value: document.getElementById('distance4Value'), size4: document.getElementById('size4'), size4Value: document.getElementById('size4Value'),
            shapeType5: document.getElementById('shapeType5'), distance5: document.getElementById('distance5'), distance5Value: document.getElementById('distance5Value'), size5: document.getElementById('size5'), size5Value: document.getElementById('size5Value'),
            // Colors
            color1: document.getElementById('color1'), color2: document.getElementById('color2'), color3: document.getElementById('color3'), color4: document.getElementById('color4'), color5: document.getElementById('color5'),
            strokeColor: document.getElementById('strokeColor'), bgColor: document.getElementById('bgColor'),
            // Save/Output Area
            saveButton: document.getElementById('saveButton'), svgOutputContainer: document.getElementById('svgOutputContainer'), svgOutputCode: document.getElementById('svgOutputCode'), closeSvgOutputButton: document.getElementById('closeSvgOutputButton')
        };

        // --- Helper Functions ---
        function generatePolygonPoints(sides, radius, centerX, centerY) { let points = ''; const angleStep = (Math.PI * 2) / sides; for (let i = 0; i < sides; i++) { const angle = i * angleStep - Math.PI / 2; const x = centerX + radius * Math.cos(angle); const y = centerY + radius * Math.sin(angle); points += `${x.toFixed(3)},${y.toFixed(3)} `; } return points.trim(); }
        function generatePetalPath(distance, size) { const halfWidth = size * 0.4; const length = size * 1.2; const tipX = distance + length; const baseX = distance; const controlX = distance + length * 0.5; return `M ${baseX.toFixed(3)},0 Q ${controlX.toFixed(3)},${halfWidth.toFixed(3)} ${tipX.toFixed(3)},0 Q ${controlX.toFixed(3)},${(-halfWidth).toFixed(3)} ${baseX.toFixed(3)},0 Z`; }
        function generateStarPoints(points, outerRadius, innerRadius, centerX, centerY) { let pointsStr = ''; const angleStep = Math.PI / points; for (let i = 0; i < 2 * points; i++) { const radius = (i % 2 === 0) ? outerRadius : innerRadius; const angle = i * angleStep - Math.PI / 2; const x = centerX + radius * Math.cos(angle); const y = centerY + radius * Math.sin(angle); pointsStr += `${x.toFixed(3)},${y.toFixed(3)} `; } return pointsStr.trim(); }

        // --- Main Drawing Function ---
        function drawMandala() {
             const numSegments = parseInt(controls.segments.value); const polygonSides = parseInt(controls.polygonSides.value); const strokeWidth = parseFloat(controls.strokeWidth.value); const strokeColor = controls.strokeColor.value;
             const shapeColors = [ controls.color1.value, controls.color2.value, controls.color3.value, controls.color4.value, controls.color5.value ];
             const shapeParams = [ { type: controls.shapeType1.value, dist: parseInt(controls.distance1.value), size: parseInt(controls.size1.value), distValEl: controls.distance1Value, sizeValEl: controls.size1Value }, { type: controls.shapeType2.value, dist: parseInt(controls.distance2.value), size: parseInt(controls.size2.value), distValEl: controls.distance2Value, sizeValEl: controls.size2Value }, { type: controls.shapeType3.value, dist: parseInt(controls.distance3.value), size: parseInt(controls.size3.value), distValEl: controls.distance3Value, sizeValEl: controls.size3Value }, { type: controls.shapeType4.value, dist: parseInt(controls.distance4.value), size: parseInt(controls.size4.value), distValEl: controls.distance4Value, sizeValEl: controls.size4Value }, { type: controls.shapeType5.value, dist: parseInt(controls.distance5.value), size: parseInt(controls.size5.value), distValEl: controls.distance5Value, sizeValEl: controls.size5Value } ];
             controls.segmentsValue.textContent = numSegments; controls.polygonSidesValue.textContent = polygonSides; controls.strokeWidthValue.textContent = strokeWidth.toFixed(1); shapeParams.forEach(p => { p.distValEl.textContent = p.dist; p.sizeValEl.textContent = p.size; });
             while (mandalaContainer.firstChild) { mandalaContainer.removeChild(mandalaContainer.firstChild); } const angle = 360 / numSegments;
             for (let i = 0; i < numSegments; i++) { const segmentGroup = document.createElementNS(svgNS, 'g'); segmentGroup.setAttribute('transform', `rotate(${i * angle}, ${cx}, ${cy})`); shapeParams.forEach((params, index) => { if (params.type !== 'none' && params.size > 0 && params.dist >= 0) { let shapeElement = null; const currentFill = shapeColors[index] || '#888888'; const currentStroke = strokeColor; try { switch(params.type) { case 'circle': shapeElement = document.createElementNS(svgNS, 'circle'); shapeElement.setAttribute('cx', String(params.dist)); shapeElement.setAttribute('cy', String(cy)); shapeElement.setAttribute('r', String(params.size)); break; case 'polygon': shapeElement = document.createElementNS(svgNS, 'polygon'); shapeElement.setAttribute('points', generatePolygonPoints(polygonSides, params.size, params.dist, cy)); break; case 'petal': shapeElement = document.createElementNS(svgNS, 'path'); shapeElement.setAttribute('d', generatePetalPath(params.dist, params.size)); break; case 'star': shapeElement = document.createElementNS(svgNS, 'polygon'); const innerRadiusStar = params.size * 0.5; shapeElement.setAttribute('points', generateStarPoints(polygonSides, params.size, innerRadiusStar, params.dist, cy)); break; } if (shapeElement) { shapeElement.setAttribute('fill', currentFill); shapeElement.setAttribute('stroke', currentStroke); shapeElement.setAttribute('stroke-width', String(strokeWidth)); shapeElement.setAttribute('vector-effect', 'non-scaling-stroke'); segmentGroup.appendChild(shapeElement); } } catch (e) { console.error(`Error creating shape ${index + 1}:`, e, params); } } }); mandalaContainer.appendChild(segmentGroup); }
        }

        // --- Update Background Color ---
        function updateBgColor() { const bgColor = controls.bgColor.value; if (mandalaBgRect) { mandalaBgRect.setAttribute('fill', bgColor); } }

        // --- Function to show SVG code ---
        function showSVGCodeToSave() { if (!mandalaContainer || !mandalaBgRect || !controls.svgOutputCode || !controls.svgOutputContainer) { console.error("Mandala container, background, or output elements not found."); alert("Error: Could not find required elements to generate SVG code."); return; } const mandalaContent = mandalaContainer.innerHTML; const currentBgColor = controls.bgColor.value; const containerTransform = mandalaContainer.getAttribute('transform') || ''; const svgWidth = mandalaBgRect.getAttribute('width'); const svgHeight = mandalaBgRect.getAttribute('height'); const svgString = `<svg width="${svgWidth}" height="${svgHeight}" viewBox="0 0 ${svgWidth} ${svgHeight}" xmlns="http://www.w3.org/2000/svg">\n    <rect x="0" y="0" width="100%" height="100%" fill="${currentBgColor}" stroke="none" />\n    <g transform="${containerTransform}">\n        ${mandalaContent}\n    </g>\n</svg>`; try { controls.svgOutputCode.value = svgString; controls.svgOutputContainer.classList.remove('hidden'); controls.svgOutputCode.focus(); controls.svgOutputCode.select(); controls.saveButton.textContent = 'Copy Code'; } catch (e) { console.error("Error displaying SVG code:", e); alert("Sorry, there was an error displaying the SVG code. Check console for details."); controls.svgOutputContainer.classList.add('hidden'); } }

        // --- Function to hide SVG code area ---
        function hideSVGCodeArea() { if (controls.svgOutputContainer && controls.saveButton) { controls.svgOutputContainer.classList.add('hidden'); controls.saveButton.textContent = 'Show SVG Code to Save'; } else { console.error("Could not find elements to hide SVG code area."); } }

        // --- Initial Draw & Event Listeners ---
        setTimeout(() => {
            drawMandala();
            if (controls.saveButton) { controls.saveButton.addEventListener('click', showSVGCodeToSave); } else { console.error("Save button element not found!"); }
            if (controls.closeSvgOutputButton) { controls.closeSvgOutputButton.addEventListener('click', hideSVGCodeArea); } else { console.error("Close SVG Output button element not found!"); }
        }, 0);




